import React, { useEffect, useRef } from 'react';

export default function MinimalGameCanvas() {
  // Reference to the <canvas> element
  const canvasRef = useRef(null);

  // We'll store the rocket position/size in a ref
  const rocketRef = useRef({ x: 300, y: 560, width: 50, height: 50 });

  // Store the falling square in a ref
  const fallingSquareRef = useRef({ x: 100, y: 0, size: 30 });

  // 1) Setup the canvas size & start the game loop
  useEffect(() => {
    if (!canvasRef.current) return;

    // Set our canvas to a known size
    const canvas = canvasRef.current;
    canvas.width = 800;
    canvas.height = 600;

    // Start the animation loop
    requestAnimationFrame(gameLoop);

    // The game loop function
    function gameLoop() {
      const ctx = canvas.getContext('2d');

      // Clear the screen
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Draw the rocket (red rectangle)
      ctx.fillStyle = 'red';
      ctx.fillRect(
        rocketRef.current.x,
        rocketRef.current.y,
        rocketRef.current.width,
        rocketRef.current.height
      );

      // Draw the falling square (blue square)
      ctx.fillStyle = 'blue';
      ctx.fillRect(
        fallingSquareRef.current.x,
        fallingSquareRef.current.y,
        fallingSquareRef.current.size,
        fallingSquareRef.current.size
      );

      // Move the square down
      fallingSquareRef.current.y += 2;

      // If it goes off the bottom, reset to the top
      if (fallingSquareRef.current.y > canvas.height) {
        fallingSquareRef.current.y = -fallingSquareRef.current.size;
      }

      // Keep looping
      requestAnimationFrame(gameLoop);
    }
  }, []);

  // 2) Mousemove to move the rocket horizontally
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const handleMouseMove = (e) => {
      // get mouse x relative to the canvas
      const rect = canvas.getBoundingClientRect();
      const mouseX = e.clientX - rect.left;

      // center the rocket around the mouse x
      rocketRef.current.x = mouseX - rocketRef.current.width / 2;

      // clamp to the canvas so it doesn't go out of bounds
      if (rocketRef.current.x < 0) {
        rocketRef.current.x = 0;
      }
      if (rocketRef.current.x + rocketRef.current.width > canvas.width) {
        rocketRef.current.x = canvas.width - rocketRef.current.width;
      }
    };

    canvas.addEventListener('mousemove', handleMouseMove);
    return () => {
      canvas.removeEventListener('mousemove', handleMouseMove);
    };
  }, []);

  return (
    <div style={{ margin: 20 }}>
      <h2>Minimal Canvas Test</h2>
      <p>
        You should see a red square at the bottom you can move with the mouse,
        and a blue square falling from the top.
      </p>
      <canvas
        ref={canvasRef}
        style={{ border: '1px solid black', display: 'block' }}
      />
    </div>
  );
}
